import { describe, expect, it } from 'vitest';
import { correlateEventsToCaptures, summarizeCaptureMatchCounts } from './fusion';
import type { Rtl433Event } from './rtl433';

describe('fusion correlations', () => {
  it('matches events to nearest capture within window', () => {
    const captures = [
      { file: 'a.u8', captureMtimeMs: 1_000 },
      { file: 'b.u8', captureMtimeMs: 10_000 },
    ];
    const events: Rtl433Event[] = [
      { whenIso: new Date(1_040).toISOString(), model: 'm', frequencyHz: null, id: null, channel: null, raw: {} },
      { whenIso: new Date(9_400).toISOString(), model: 'm', frequencyHz: null, id: null, channel: null, raw: {} },
      { whenIso: new Date(30_000).toISOString(), model: 'm', frequencyHz: null, id: null, channel: null, raw: {} },
    ];
    const matches = correlateEventsToCaptures(captures, events, 1_000);
    expect(matches.length).toBe(2);
    expect(matches[0]?.captureIndex).toBe(0);
    expect(matches[1]?.captureIndex).toBe(1);
    expect(summarizeCaptureMatchCounts(captures, matches)).toEqual([1, 1]);
  });
});
